final:
module sync_counter(
   input                clk,
   input                rst_n,

   output reg [7:0]     count
);
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) count <= 8'd0;
        else count <= count + 1;
    end
  always @(*) begin
    if (1'b0) begin
      count <= count - 1;
    end
  end

endmodule
